lines = data_str.strip().split('\n')
items = []

keys = [
    "id", "Name", "Description", "Category", "TypeID", "TypeName", 
    "PhysicalFormID", "PhysicalFormName", "StorageFormID", "StorageFormName", 
    "BuyConsumeMeasuringUnitID", "BuyConsumeMeasuringUnitName", "MinStockForAlert", 
    "AlertStaffID", "AlertStaffName", "BranchID", "DepartmentID", "CreatedStaffID", 
    "CreatedDateTime", "UpdatedStaffID", "UpdatedDateTime", "IsRowDeleted", 
    "CurrentStock", "Balance", "PackSize", "Qty", "PackSizeUnits", "ItemType", 
    "IssueDate", "StockUnit", "PurchaseUnit", "IssueUnit", "UsageDescription", 
    "ItemCode", "ConversionLogic"
]

for line in lines:
    # Use regex to find values between single quotes or NULL
    values = re.findall(r"'(.*?)'|NULL", line)
    # Re-process to handle NULLs correctly (re.findall returns empty strings for NULL if not careful)
    # Actually, a better way is to split by comma and strip.
    raw_values = []
    current_val = ""
    in_quotes = False
    for char in line:
        if char == "'":
            in_quotes = not in_quotes
        elif char == "," and not in_quotes:
            raw_values.append(current_val.strip())
            current_val = ""
        else:
            current_val += char
    raw_values.append(current_val.strip())
    
    processed_values = []
    for rv in raw_values:
        if rv == "NULL":
            processed_values.append(None)
        elif rv.startswith("'") and rv.endswith("'"):
            processed_values.append(rv[1:-1])
        else:
            # Handle cases where NULL might be part of string or number
            processed_values.append(rv)

    item = {}
    for i in range(len(keys)):
        val = processed_values[i] if i < len(processed_values) else None
        # Convert numeric IDs to integers if possible
        if keys[i] == "id" and val is not None:
            try:
                val = int(val)
            except:
                pass
        item[keys[i]] = val
    items.append(item)

# Load current db.json
with open('src/assets/data/db.json', 'r') as f:
    db = json.load(f)

db['inventory_items'] = items

# Save updated db.json
with open('src/assets/data/db.json', 'w') as f:
    json.dump(db, f, indent=2)

print("Successfully updated db.json with " + str(len(items)) + " items.")
